def prp_fr_mdl(
                  img:np.ndarray # shape of height, width
    ):
    'Prepare for model prediciton'
    max_ = np.max(img)
    if max_ > 2:
        img = img/255.0
    img = np.expand_dims(img, axis=-1)[None, ...]
    img = img.astype(np.float32)
    return img

