def dilation_(
    img:tf.Tensor,
    threshold:tf.float32,
              t_:int=3):
    img = img > threshold
    img = tf.cast(img, tf.float32)
    for i in range(t_):
        img = tf.keras.layers.MaxPool2D(pool_size=(3, 3), strides=[1,1], padding='same')(img)
    return img

    
    

