def erosion_(msk, t_=3):
    msk = msk.astype(np.float32)
    msk = msk * (-1)
    if len(msk.shape) ==2:
        msk = msk[None, ..., None]
    elif len(msk.shape) ==3:
            msk = msk[None, ...]
    else:
        msk = msk
    for i in range(t_):
        msk = tf.keras.layers.MaxPool2D(pool_size=(3, 3), strides=[1,1], padding='same')(msk)
    msk = msk * (-1)
    return msk

